pub(crate) fn register_tick_classes(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add_class::<CalendarDay>()?;
    m.add_class::<EodTick>()?;
    m.add_class::<GreeksTick>()?;
    m.add_class::<InterestRateTick>()?;
    m.add_class::<IvTick>()?;
    m.add_class::<MarketValueTick>()?;
    m.add_class::<OhlcTick>()?;
    m.add_class::<OpenInterestTick>()?;
    m.add_class::<OptionContract>()?;
    m.add_class::<PriceTick>()?;
    m.add_class::<QuoteTick>()?;
    m.add_class::<TradeQuoteTick>()?;
    m.add_class::<TradeTick>()?;
    Ok(())
}

